svg.script:

var SVG_NS = 'http://www.w3.org/2000/svg';
var scene = document.getElementById('scene');

var COLOR_DIM = '#0d4a5a';
var COLOR_BASE = '#1a7a8f';
var COLOR_BRIGHT = '#3aeaf5';
var COLOR_WHITE = '#b0f4ff';

// ── Tree geometry — angular, conical wireframes ──────────────

// Large left tree — angular canopy built from triangular facets
var leftTreeNodes = [
  // Apex
  {x:370, y:160},   // 0 — top peak
  // Upper tier (narrow)
  {x:340, y:210},   // 1
  {x:400, y:205},   // 2
  // Mid-upper tier
  {x:295, y:260},   // 3
  {x:355, y:248},   // 4
  {x:415, y:252},   // 5
  {x:470, y:268},   // 6
  // Mid tier
  {x:260, y:318},   // 7
  {x:320, y:305},   // 8
  {x:380, y:298},   // 9
  {x:440, y:308},   // 10
  {x:505, y:325},   // 11
  // Lower canopy
  {x:235, y:375},   // 12
  {x:295, y:358},   // 13
  {x:358, y:348},   // 14
  {x:420, y:355},   // 15
  {x:485, y:370},   // 16
  {x:540, y:390},   // 17
  // Canopy base
  {x:270, y:428},   // 18
  {x:340, y:415},   // 19
  {x:400, y:410},   // 20
  {x:465, y:420},   // 21
  {x:525, y:438},   // 22
  // Trunk
  {x:365, y:465},   // 23
  {x:385, y:465},   // 24
  {x:360, y:580},   // 25
  {x:390, y:580},   // 26
  {x:355, y:760},   // 27
  {x:395, y:760},   // 28
];

var leftTreeEdges = [
  // Apex to upper
  [0,1],[0,2],
  // Upper tier
  [1,2],
  // Upper to mid-upper
  [1,3],[1,4],[2,4],[2,5],[2,6],
  // Mid-upper horizontal
  [3,4],[4,5],[5,6],
  // Mid-upper to mid
  [3,7],[3,8],[4,8],[4,9],[5,9],[5,10],[6,10],[6,11],
  // Mid horizontal
  [7,8],[8,9],[9,10],[10,11],
  // Mid to lower
  [7,12],[7,13],[8,13],[8,14],[9,14],[9,15],[10,15],[10,16],[11,16],[11,17],
  // Lower horizontal
  [12,13],[13,14],[14,15],[15,16],[16,17],
  // Lower to base
  [12,18],[13,18],[13,19],[14,19],[14,20],[15,20],[15,21],[16,21],[16,22],[17,22],
  // Base horizontal
  [18,19],[19,20],[20,21],[21,22],
  // Trunk connections
  [19,23],[20,23],[20,24],[21,24],
  [23,25],[24,26],[25,27],[26,28],
  [23,24],[25,26],
];

// Right tree — mirrored with slight offset
var rightTreeNodes = leftTreeNodes.map(function(n) {
  return {x: 1600 - n.x + 30, y: n.y + 6};
});
var rightTreeEdges = leftTreeEdges.slice();

// Small background trees — simple angular shapes
var smallTrees = [
  { // Tree A
    nodes: [
      {x:615, y:455}, {x:600, y:495}, {x:630, y:492},
      {x:585, y:535}, {x:612, y:528}, {x:640, y:532}, {x:660, y:545},
      {x:612, y:565}, {x:618, y:565},
      {x:610, y:650}, {x:620, y:650},
      {x:608, y:760}, {x:622, y:760}
    ],
    edges: [
      [0,1],[0,2],[1,2],
      [1,3],[1,4],[2,4],[2,5],[2,6],
      [3,4],[4,5],[5,6],
      [4,7],[5,8],[7,8],
      [7,9],[8,10],[9,10],
      [9,11],[10,12]
    ]
  },
  { // Tree B
    nodes: [
      {x:735, y:468}, {x:720, y:508}, {x:750, y:505},
      {x:705, y:545}, {x:732, y:538}, {x:758, y:542}, {x:778, y:555},
      {x:730, y:572}, {x:740, y:572},
      {x:728, y:660}, {x:742, y:660},
      {x:726, y:760}, {x:744, y:760}
    ],
    edges: [
      [0,1],[0,2],[1,2],
      [1,3],[1,4],[2,4],[2,5],[2,6],
      [3,4],[4,5],[5,6],
      [4,7],[5,8],[7,8],
      [7,9],[8,10],[9,10],
      [9,11],[10,12]
    ]
  },
  { // Tree C — center, taller
    nodes: [
      {x:840, y:420}, {x:825, y:465}, {x:855, y:462},
      {x:808, y:505}, {x:835, y:498}, {x:862, y:502}, {x:882, y:518},
      {x:822, y:545}, {x:852, y:542},
      {x:834, y:572}, {x:846, y:572},
      {x:832, y:660}, {x:848, y:660},
      {x:830, y:760}, {x:850, y:760}
    ],
    edges: [
      [0,1],[0,2],[1,2],
      [1,3],[1,4],[2,4],[2,5],[2,6],
      [3,4],[4,5],[5,6],
      [3,7],[4,7],[5,8],[6,8],
      [7,8],
      [7,9],[8,10],[9,10],
      [9,11],[10,12],
      [11,13],[12,14]
    ]
  },
  { // Tree D
    nodes: [
      {x:955, y:462}, {x:940, y:502}, {x:970, y:498},
      {x:925, y:540}, {x:952, y:532}, {x:978, y:538}, {x:998, y:552},
      {x:950, y:568}, {x:960, y:568},
      {x:948, y:658}, {x:962, y:658},
      {x:946, y:760}, {x:964, y:760}
    ],
    edges: [
      [0,1],[0,2],[1,2],
      [1,3],[1,4],[2,4],[2,5],[2,6],
      [3,4],[4,5],[5,6],
      [4,7],[5,8],[7,8],
      [7,9],[8,10],[9,10],
      [9,11],[10,12]
    ]
  },
  { // Tree E
    nodes: [
      {x:1065, y:472}, {x:1050, y:512}, {x:1080, y:508},
      {x:1035, y:548}, {x:1062, y:540}, {x:1088, y:545}, {x:1108, y:558},
      {x:1058, y:575}, {x:1072, y:575},
      {x:1056, y:660}, {x:1074, y:660},
      {x:1054, y:760}, {x:1076, y:760}
    ],
    edges: [
      [0,1],[0,2],[1,2],
      [1,3],[1,4],[2,4],[2,5],[2,6],
      [3,4],[4,5],[5,6],
      [4,7],[5,8],[7,8],
      [7,9],[8,10],[9,10],
      [9,11],[10,12]
    ]
  }
];

// ── Ground plane — sparse perspective grid ────────────────────
var groundGroup = createEl('g', {'opacity': '0.15'});

// Horizontal lines receding
for (var gy = 720; gy <= 880; gy += 40) {
  var fade = (gy - 720) / 160;
  var hLine = createEl('line', {
    x1: 100 + (1 - fade) * 200, y1: gy,
    x2: 1500 - (1 - fade) * 200, y2: gy,
    stroke: COLOR_DIM, 'stroke-width': String(0.5 + fade * 0.5), opacity: String(0.2 + fade * 0.4)
  });
  groundGroup.appendChild(hLine);
}
scene.appendChild(groundGroup);

// ── Rendering ──────────────────────────────────────────────────

function createEl(tag, attrs) {
  var el = document.createElementNS(SVG_NS, tag);
  for (var k in attrs) {
    if (attrs.hasOwnProperty(k)) el.setAttribute(k, attrs[k]);
  }
  return el;
}

function drawTree(nodes, edges, opacity, lineWidth) {
  var g = createEl('g', {'filter': 'url(#glow)', 'opacity': opacity || '1'});
  var edgeEls = [];
  var nodeEls = [];
  var lw = lineWidth || 1.0;

  // Draw edges only — clean wireframe, no dots
  edges.forEach(function(e) {
    var a = nodes[e[0]], b = nodes[e[1]];
    var line = createEl('line', {
      x1: a.x, y1: a.y, x2: b.x, y2: b.y,
      stroke: COLOR_DIM, 'stroke-width': String(lw), 'stroke-linecap': 'round'
    });
    g.appendChild(line);
    edgeEls.push({el: line, from: e[0], to: e[1]});
  });

  // Vertex dots — tiny, barely visible (just enough to catch light)
  nodes.forEach(function(n, i) {
    var circle = createEl('circle', {
      cx: n.x, cy: n.y, r: '1.0',
      fill: COLOR_BASE, opacity: '0.5'
    });
    g.appendChild(circle);
    nodeEls.push(circle);
  });

  scene.appendChild(g);
  return {group: g, edges: edgeEls, nodes: nodeEls, data: nodes};
}

var treesRendered = [];
treesRendered.push(drawTree(leftTreeNodes, leftTreeEdges, '1', 1.1));
treesRendered.push(drawTree(rightTreeNodes, rightTreeEdges, '1', 1.1));
smallTrees.forEach(function(t) {
  treesRendered.push(drawTree(t.nodes, t.edges, '0.55', 0.8));
});

// ── Particle animation ─────────────────────────────────────────

var particles = [];
var PARTICLE_POOL_SIZE = 12;

function spawnParticle() {
  var treeIdx = Math.floor(Math.random() * treesRendered.length);
  if (Math.random() < 0.7) treeIdx = Math.random() < 0.5 ? 0 : 1;

  var tree = treesRendered[treeIdx];
  var edgeIdx = Math.floor(Math.random() * tree.edges.length);
  var edge = tree.edges[edgeIdx];
  var fromNode = tree.data[edge.from];
  var toNode = tree.data[edge.to];

  if (Math.random() < 0.5) {
    var tmp = fromNode;
    fromNode = toNode;
    toNode = tmp;
    var tmpIdx = edge.from;
    edge = {el: edge.el, from: edge.to, to: tmpIdx};
  }

  var dx = toNode.x - fromNode.x;
  var dy = toNode.y - fromNode.y;
  var dist = Math.sqrt(dx * dx + dy * dy);
  var duration = dist * 15 + 600;

  var particleEl = createEl('circle', {
    cx: fromNode.x, cy: fromNode.y, r: '1.5',
    fill: COLOR_BRIGHT, opacity: '0', filter: 'url(#particle-glow)'
  });
  scene.appendChild(particleEl);

  return {
    el: particleEl,
    fromX: fromNode.x, fromY: fromNode.y,
    toX: toNode.x, toY: toNode.y,
    edgeEl: edge.el,
    toNodeEl: tree.nodes[edge.to !== undefined ? edge.to : 0],
    startTime: performance.now() + Math.random() * 800,
    duration: duration,
    treeIdx: treeIdx,
    alive: true
  };
}

for (var i = 0; i < PARTICLE_POOL_SIZE; i++) {
  var p = spawnParticle();
  p.startTime = performance.now() + i * 500 + Math.random() * 1000;
  particles.push(p);
}

var pulsingNodes = [];

function pulseNode(nodeEl) {
  pulsingNodes.push({
    el: nodeEl,
    startTime: performance.now(),
    duration: 350
  });
}

function animate(now) {
  particles.forEach(function(p, idx) {
    if (!p.alive) return;

    var elapsed = now - p.startTime;
    if (elapsed < 0) {
      p.el.setAttribute('opacity', '0');
      return;
    }

    var t = elapsed / p.duration;
    if (t >= 1) {
      pulseNode(p.toNodeEl);

      p.edgeEl.setAttribute('stroke', COLOR_BASE);
      p.edgeEl.setAttribute('stroke-width', '1.8');
      setTimeout(function(el, lw) {
        return function() {
          el.setAttribute('stroke', COLOR_DIM);
          el.setAttribute('stroke-width', lw);
        };
      }(p.edgeEl, p.treeIdx < 2 ? '1.1' : '0.8'), 250);

      scene.removeChild(p.el);
      var newP = spawnParticle();
      newP.startTime = now + 500 + Math.random() * 2500;
      particles[idx] = newP;
      return;
    }

    var easedT = t < 0.5 ? 2 * t * t : 1 - Math.pow(-2 * t + 2, 2) / 2;

    var cx = p.fromX + (p.toX - p.fromX) * easedT;
    var cy = p.fromY + (p.toY - p.fromY) * easedT;

    p.el.setAttribute('cx', cx);
    p.el.setAttribute('cy', cy);
    // Fade in and out
    var alpha = Math.sin(t * Math.PI);
    p.el.setAttribute('opacity', String(0.5 * alpha + 0.15));

    // Subtly brighten edge
    var brightness = 0.2 + 0.3 * alpha;
    p.edgeEl.setAttribute('stroke', lerpColor(COLOR_DIM, COLOR_BASE, brightness));
  });

  // Pulsing nodes — subtle
  for (var j = pulsingNodes.length - 1; j >= 0; j--) {
    var pn = pulsingNodes[j];
    var pt = (now - pn.startTime) / pn.duration;
    if (pt >= 1) {
      pn.el.setAttribute('r', '1.0');
      pn.el.setAttribute('fill', COLOR_BASE);
      pn.el.setAttribute('opacity', '0.5');
      pulsingNodes.splice(j, 1);
      continue;
    }
    var pulseAmount = Math.sin(pt * Math.PI);
    pn.el.setAttribute('r', String(1.0 + 2.0 * pulseAmount));
    pn.el.setAttribute('fill', lerpColor(COLOR_BASE, COLOR_BRIGHT, pulseAmount * 0.7));
    pn.el.setAttribute('opacity', String(0.5 + 0.5 * pulseAmount));
  }

  requestAnimationFrame(animate);
}

function lerpColor(a, b, t) {
  var ar = parseInt(a.slice(1,3), 16), ag = parseInt(a.slice(3,5), 16), ab = parseInt(a.slice(5,7), 16);
  var br = parseInt(b.slice(1,3), 16), bg = parseInt(b.slice(3,5), 16), bb = parseInt(b.slice(5,7), 16);
  var rr = Math.round(ar + (br - ar) * t);
  var rg = Math.round(ag + (bg - ag) * t);
  var rb = Math.round(ab + (bb - ab) * t);
  return '#' + ((1 << 24) + (rr << 16) + (rg << 8) + rb).toString(16).slice(1);
}

requestAnimationFrame(animate);
